using NewSmartAIFactory.CompanyApi.Models;using NewSmartAIFactory.CompanyApi.Services;using Npgsql;
namespace NewSmartAIFactory.CompanyApi.Endpoints;
public static class AgentRunEndpoints{public static IEndpointRouteBuilder MapAgentRunEndpoints(this IEndpointRouteBuilder app){var g=app.MapGroup("/api/agent-runs").WithTags("Agent Runs");g.MapGet("/",async(string? agentId,string? status,int? limit,AgentRunLogService s,CancellationToken t)=>Results.Ok(await s.ListAsync(agentId,status,limit??50,t)));g.MapGet("/{id:guid}",async(Guid id,AgentRunLogService s,CancellationToken t)=>{var x=await s.GetAsync(id,t);return x is null?Results.NotFound():Results.Ok(x);});g.MapPost("/",async(StartAgentRunRequest r,AgentRunLogService s,CancellationToken t)=>{if(string.IsNullOrWhiteSpace(r.AgentId)||string.IsNullOrWhiteSpace(r.InputText))return Results.BadRequest(new{error="required_fields",message="AgentId and InputText are required."});try{return Results.Created("/api/agent-runs",await s.StartAsync(r,t));}catch(PostgresException ex)when(ex.SqlState==PostgresErrorCodes.ForeignKeyViolation){return Results.BadRequest(new{error="invalid_reference",message="Agent, task, or project does not exist."});}});g.MapPost("/{id:guid}/complete",async(Guid id,CompleteAgentRunRequest r,AgentRunLogService s,CancellationToken t)=>{if(r.Status is not("Succeeded" or "Failed" or "Cancelled"))return Results.BadRequest(new{error="invalid_status",message="Status must be Succeeded, Failed, or Cancelled."});var x=await s.CompleteAsync(id,r,t);return x is null?Results.NotFound():Results.Ok(x);});return app;}}
